#include <stdio.h>
#include <string.h>
int main() {
    char P[1000001];
    int Q, L, R;
    char a, b;
    scanf("%s", P);
    scanf("%d", &Q);
    while (Q--) {
        scanf(" %c %c %d %d", &a, &b, &L, &R);
        int count = 0;
        for (int i = L - 1; i < R; i++) {
            for (int j = i + 1; j <= R; j++) {
                if (P[i] == a && P[j] == b && P[i] != P[j]) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

