code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String P = sc.next();
        int Q = sc.nextInt();
        while (Q-- > 0) {
            char a = sc.next().charAt(0);
            char b = sc.next().charAt(0);
            int L = sc.nextInt();
            int R = sc.nextInt();
            int count = 0;
            for (int i = L - 1; i < R; i++) {
                for (int j = i + 1; j <= R; j++) {
                    if (P.charAt(i) == a && P.charAt(j) == b && P.charAt(i) != P.charAt(j)) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

